import re

def extract_copies(desc):
    if not desc:
        return None
    desc = desc.lower()
    m = re.search(r'(?:appearing|appears|copied|duplicated|repeated|seen|appears?)\s+(\d+)\s+times', desc)
    if m:
        return int(m.group(1))
    m = re.search(r'(\d+)\s+times', desc)
    if m:
        return int(m.group(1))
    return None

swift_records = []
for r in records:
    path = r.get('sample_path','') or ''
    desc = r.get('repo_data_description','') or ''
    if path.lower().endswith('.swift'):
        copies = extract_copies(desc)
        swift_records.append({'id': r.get('id'), 'sample_repo_name': r.get('sample_repo_name'), 'sample_path': path, 'copies': copies, 'repo_data_description': desc})

# find the id with the maximum copies (non-null)
max_rec = None
for rec in swift_records:
    if rec['copies'] is None:
        continue
    if max_rec is None or rec['copies'] > max_rec['copies']:
        max_rec = rec

# If tie, keep them all
max_copies = max_rec['copies'] if max_rec else None
max_list = [r for r in swift_records if r['copies']==max_copies] if max_copies is not None else []

output = {'max_copies': max_copies, 'records': max_list[:50]}
print('__RESULT__:')
print(json.dumps(output))

